# Example: GitHub Actions cron job to alert on stale postmortem items
import datetime
from github import Github

def check_stale_action_items():
    g = Github(token)
    repo = g.get_repo("org/ai-platform")

    for issue in repo.get_issues(labels=["postmortem-action"], state="open"):
        sla_label = next(
            (l for l in issue.labels if l.name.startswith("sev-")), None
        )
        if not sla_label:
            continue

        sev = sla_label.name.split("-")[1]
        sla_days = {"1": 3, "2": 7, "3": 30}[sev]

        published_at = get_postmortem_published_date(issue)
        days_elapsed = (datetime.date.today() - published_at).days
        days_remaining = sla_days - days_elapsed

        if days_remaining <= 1:
            post_slack_alert(
                channel="#eng-incidents",
                message=(
                    f"BREACH IMMINENT: SEV-{sev} action item "
                    f"'{issue.title}' due in {days_remaining}d. "
                    f"Owner: @{issue.assignee.login}"
                )
            )
        elif days_remaining <= 2:
            post_slack_alert(
                channel=f"@{issue.assignee.login}",
                message=(
                    f"SLA reminder: '{issue.title}' due in {days_remaining}d"
                )
            )
